      "id": "notes/books/2015-01-01_storytelling-with-data-knaflic",
      "kind": "book",
      "label": "Storytelling with Data: A Data Visualization Guide for Business Professionals",
      "authors": [
        "Cole Nussbaumer Knaflic"
      ],
      "year": "2015",
      "venue": "",
